      91: static int GrowBitfield(AclBits * bfp, int len, int delta, int defaultbit)
      92: {
      93: 	AclBits n, o = *bfp;
      94: 
>>    95: 	if (!(n = (AclBits) calloc(1, (unsigned long)(&ACLBYTE((char *)NULL, len + delta) + 1))))
      96: 		return -1;
      97: 	for (int i = 0; i < (len + delta); i++) {
      98: 		if (((i < len) && (ACLBIT(i) & ACLBYTE(o, i))) || ((i >= len) && (defaultbit)))
      99: 			ACLBYTE(n, i) |= ACLBIT(i);
     100: 	}
     101: 	if (len)
     102: 		free((char *)o);
     103: 	*bfp = n;
     104: 	return 0;
     105: }

     142: int UserAdd(char *name, struct acluser **up)
     143: {
     144: 	if (!up)
     145: 		up = FindUserPtr(name);
     146: 	if (*up) {
     147: 		return 1;
     148: 	}
     149: 	if (strcmp("none", name))	/* "none" is a reserved word */
     150: 		*up = calloc(1, sizeof(struct acluser));
     151: 	if (!*up)
     152: 		return -1;
     153: 	(*up)->u_plop.buf = NULL;
     154: 	(*up)->u_plop.len = 0;
     155: 	(*up)->u_plop.enc = 0;
     156: 	(*up)->u_Esc = DefaultEsc;
     157: 	(*up)->u_MetaEsc = DefaultMetaEsc;
     158: 	strncpy((*up)->u_name, name, MAXLOGINLEN);
     159: 	(*up)->u_detachwin = -1;
     160: 	(*up)->u_detachotherwin = -1;
     161: 
     162: 	(*up)->u_group = NULL;
     163: 	/* now find an unused index */
     164: 	for ((*up)->u_id = 0; (*up)->u_id < maxusercount; (*up)->u_id++)
     165: 		if (!(ACLBIT((*up)->u_id) & ACLBYTE(userbits, (*up)->u_id)))
     166: 			break;
     167: 	if ((*up)->u_id == maxusercount) {
     168: 		/* the bitfields are full, grow a chunk */
     169: 		/* first, the used_uid_indicator: */
     170: 		if (GrowBitfield(&userbits, maxusercount, USER_CHUNK, 0)) {
     171: 			free((char *)*up);
     172: 			*up = NULL;
     173: 			return -1;
     174: 		}
     175: 		/* second, default command bits  */
     176: 		/* (only if we generate commands dynamically) */
     177: /*
     178:       for (int j = 0; j < ACL_BITS_PER_CMD; j++)
     179: 	if (GrowBitfield(&default_c_userbits[j], maxusercount, USER_CHUNK, 
     180: 	    default_c_bit[j]))
     181: 	  {
     182: 	    free((char *)*up); *up = NULL; return -1;
     183: 	  }
     184: */
     185: 		/* third, the bits for each commands */
     186: 		for (int j = 0; j <= RC_LAST; j++) {
     187: 			for (int i = 0; i < ACL_BITS_PER_CMD; i++)
     188: 				if (GrowBitfield(&comms[j].userbits[i], maxusercount, USER_CHUNK, default_c_bit[i])) {
     189: 					free((char *)*up);
     190: 					*up = NULL;
     191: 					return -1;
     192: 				}
     193: 		}
     194: 		/* fourth, default window creation bits per user */
     195: 		for (struct acluser *u = users; u != *up; u = u->u_next) {
     196: 			for (int j = 0; j < ACL_BITS_PER_WIN; j++) {
     197: 				if (GrowBitfield(&u->u_umask_w_bits[j], maxusercount, USER_CHUNK, default_w_bit[j])) {
     198: 					free((char *)*up);
     199: 					*up = NULL;
     200: 					return -1;
     201: 				}
     202: 			}
     203: 		}
     204: 
     205: 		/* fifth, the bits for each window */
     206: 		/* keep these in sync with NewWindowAcl() */
     207: 		for (Window *w = mru_window; w; w = w->w_prev_mru) {
     208: 			/* five a: the access control list */
     209: 			for (int j = 0; j < ACL_BITS_PER_WIN; j++)
     210: 				if (GrowBitfield(&w->w_userbits[j], maxusercount, USER_CHUNK, default_w_bit[j])) {
     211: 					free((char *)*up);
     212: 					*up = NULL;
     213: 					return -1;
     214: 				}
     215: 			/* five b: the activity notify list */
     216: 			/* five c: the silence notify list */
     217: 			if (GrowBitfield(&w->w_mon_notify, maxusercount, USER_CHUNK, 0) ||
     218: 			    GrowBitfield(&w->w_lio_notify, maxusercount, USER_CHUNK, 0)) {
     219: 				free((char *)*up);
     220: 				*up = NULL;
     221: 				return -1;
     222: 			}
     223: 		}
     224: 		maxusercount += USER_CHUNK;
     225: 	}
     226: 
     227: 	/* mark the user-entry as "in-use" */
     228: 	ACLBYTE(userbits, (*up)->u_id) |= ACLBIT((*up)->u_id);
     229: 
     230: 	/* user id 0 is the session creator, he has all rights */
     231: 	if ((*up)->u_id == 0)
     232: 		AclSetPerm(NULL, *up, "+a", "#?");
     233: 
     234: 	/* user nobody has a fixed set of rights: */
     235: 	if (!strcmp((*up)->u_name, "nobody")) {
     236: 		AclSetPerm(NULL, *up, "-rwx", "#?");
     237: 		AclSetPerm(NULL, *up, "+x", "su");
     238: 		AclSetPerm(NULL, *up, "+x", "detach");
     239: 		AclSetPerm(NULL, *up, "+x", "displays");
     240: 		AclSetPerm(NULL, *up, "+x", "version");
     241: 	}
     242: 
     243: 	/* 
     244: 	 * Create his umask:
     245: 	 * Give default_w_bit's for all users, 
     246: 	 * but allow himself everything on "his" windows.
     247: 	 */
>>   248: 	for (int j = 0; j < ACL_BITS_PER_WIN; j++) {
>>   249: 		if (GrowBitfield(&(*up)->u_umask_w_bits[j], 0, maxusercount, default_w_bit[j])) {
     250: 			free((char *)*up);
     251: 			*up = NULL;
     252: 			return -1;
     253: 		}
     254: 		ACLBYTE((*up)->u_umask_w_bits[j], (*up)->u_id) |= ACLBIT((*up)->u_id);
     255: 	}
     256: 	return 0;
     257: }

     370: int AclLinkUser(char *from, char *to)
     371: {
     372: 	struct acluser **u1, **u2;
     373: 	struct aclusergroup **g;
     374: 
>>   375: 	if (!*(u1 = FindUserPtr(from)) && UserAdd(from, u1))
     376: 		return -1;
>>   377: 	if (!*(u2 = FindUserPtr(to)) && UserAdd(to, u2))
     378: 		return -1;	/* hmm, could not find both users. */
     379: 
     380: 	if (*FindGroupPtr(&(*u2)->u_group, *u1, 1))
     381: 		return 1;	/* cyclic link detected! */
     382: 	if (*(g = FindGroupPtr(&(*u1)->u_group, *u2, 0)))
     383: 		return 2;	/* aha, we are already linked! */
     384: 
     385: 	if (!(*g = (struct aclusergroup *)malloc(sizeof(struct aclusergroup))))
     386: 		return -1;	/* Could not alloc link. Poor screen */
     387: 	(*g)->u = (*u2);
     388: 	(*g)->next = NULL;
     389: 	return 0;
     390: }

