     269: int UserDel(char *name, struct acluser **up)
     270: {
     271: 	struct acluser *u;
     272: 	Display *old, *next;
     273: 
     274: 	if (!up)
     275: 		up = FindUserPtr(name);
>>   276: 	if (!(u = *up))
     277: 		return -1;
     278: 	old = display;
     279: 	for (display = displays; display; display = next) {
     280: 		next = display->d_next;	/* read the next ptr now, Detach may zap it. */
     281: 		if (D_user != u)
     282: 			continue;
     283: 		if (display == old)
     284: 			old = NULL;
     285: 		Detach(D_REMOTE);
     286: 	}
     287: 	display = old;
     288: 	*up = u->u_next;
     289: 
     290: 	for (up = &users; *up; up = &(*up)->u_next) {
     291: 		/* unlink all group references to this user */
     292: 		struct aclusergroup **g = &(*up)->u_group;
     293: 
     294: 		while (*g) {
     295: 			if ((*g)->u == u) {
     296: 				struct aclusergroup *next = (*g)->next;
     297: 
     298: 				free((char *)(*g));
     299: 				*g = next;
     300: 			} else
     301: 				g = &(*g)->next;
     302: 		}
     303: 	}
     304: 	ACLBYTE(userbits, u->u_id) &= ~ACLBIT(u->u_id);
     305: 	/* restore the bits in his slot to default: */
     306: 	AclSetPerm(NULL, u, default_w_bit[ACL_READ] ? "+r" : "-r", "#");
     307: 	AclSetPerm(NULL, u, default_w_bit[ACL_WRITE] ? "+w" : "-w", "#");
     308: 	AclSetPerm(NULL, u, default_w_bit[ACL_EXEC] ? "+x" : "-x", "#");
     309: 	AclSetPerm(NULL, u, default_c_bit[ACL_EXEC] ? "+x" : "-x", "?");
     310: 	for (int i = 0; i < ACL_BITS_PER_WIN; i++)
     311: 		free((char *)u->u_umask_w_bits[i]);
     312: 	UserFreeCopyBuffer(u);
     313: 	free((char *)u);
     314: 	if (!users) {
     315: 		Finit(0);	/* Destroying whole session. Noone could ever attach again. */
     316: 	}
     317: 	return 0;
     318: }

