    1485: int LoadFontTranslation(int font, char *file)
    1486: {
    1487: 	char buf[1024], *myfile;
    1488: 	FILE *f;
    1489: 	int i;
    1490: 	int fo;
    1491: 	int x, u, c, ok;
    1492: 	unsigned short (*p)[2], (*tab)[2];
    1493: 
    1494: 	myfile = file;
    1495: 	if (myfile == NULL) {
    1496: 		if (font == 0 || screenencodings == NULL)
    1497: 			return -1;
    1498: 		if (strlen(screenencodings) > ARRAY_SIZE(buf) - 10)
    1499: 			return -1;
    1500: 		sprintf(buf, "%s/%02x", screenencodings, font & 0xff);
    1501: 		myfile = buf;
    1502: 	}
    1503: 	if ((f = secfopen(myfile, "r")) == NULL)
    1504: 		return -1;
    1505: 	i = ok = 0;
    1506: 	for (;;) {
    1507: 		for (; i < 12; i++)
    1508: 			if (getc(f) != "ScreenI2UTF8"[i])
    1509: 				break;
    1510: 		if (getc(f) != 0)	/* format */
    1511: 			break;
    1512: 		fo = getc(f);	/* id */
    1513: 		if (fo == EOF)
    1514: 			break;
    1515: 		if (font != -1 && font != fo)
    1516: 			break;
    1517: 		i = getc(f);
    1518: 		x = getc(f);
    1519: 		if (x == EOF)
    1520: 			break;
    1521: 		i = i << 8 | x;
    1522: 		getc(f);
    1523: 		while ((x = getc(f)) && x != EOF)
    1524: 			getc(f);	/* skip font name (padded to 2 bytes) */
>>  1525: 		if ((p = malloc(sizeof(*p) * (i + 1) * 4)) == NULL)
    1526: 			break;
    1527: 		tab = p;
    1528: 		while (i > 0) {
    1529: 			x = getc(f);
    1530: 			x = x << 8 | getc(f);
    1531: 			u = getc(f);
    1532: 			c = getc(f);
    1533: 			u = u << 8 | c;
    1534: 			if (c == EOF)
    1535: 				break;
    1536: 			(*p)[0] = x;
    1537: 			(*p)[1] = u;
    1538: 			p++;
    1539: 			i--;
    1540: 		}
    1541: 		(*p)[0] = 0;
    1542: 		(*p)[1] = 0;
>>  1543: 		if (i || (tab[0][0] & 0x8000)) {
    1544: 			free(tab);
    1545: 			break;
    1546: 		}
    1547: 		if (recodetabs[fo].tab && (recodetabs[fo].flags & RECODETAB_ALLOCED) != 0)
    1548: 			free(recodetabs[fo].tab);
    1549: 		recodetabs[fo].tab = tab;
    1550: 		recodetabs[fo].flags = RECODETAB_ALLOCED;
    1551: 		c = getc(f);
    1552: 		if (c == EOF) {
    1553: 			ok = 1;
    1554: 			break;
    1555: 		}
    1556: 		if (c != 'S')
    1557: 			break;
    1558: 		i = 1;
    1559: 	}
    1560: 	fclose(f);
    1561: 	if (font != -1 && file == NULL && recodetabs[font].flags == 0)
    1562: 		recodetabs[font].flags = RECODETAB_TRIED;
    1563: 	return ok ? 0 : -1;
    1564: }

     140: int StartRc(char *rcfilename, int nopanic)
     141: {
     142: 	int argc, len;
     143: 	char *p, *cp;
     144: 	char buf[2048];
     145: 	char *args[MAXARGS];
     146: 	int argl[MAXARGS];
     147: 	FILE *fp;
     148: 	char *oldrc_name = rc_name;
     149: 
     150: 	/* always fix termcap/info capabilities */
     151: 	extra_incap = CatExtra("TF", extra_incap);
     152: 
     153: 	/* Special settings for vt100 and others */
     154: 	if (display && (!strncmp(D_termname, "vt", 2) || !strncmp(D_termname, "xterm", 5)))
     155: 		extra_incap =
>>   156: 		    CatExtra
     157: 		    ("xn:f0=\033Op:f1=\033Oq:f2=\033Or:f3=\033Os:f4=\033Ot:f5=\033Ou:f6=\033Ov:f7=\033Ow:f8=\033Ox:f9=\033Oy:f.=\033On:f,=\033Ol:fe=\033OM:f+=\033Ok:f-=\033Om:f*=\033Oj:f/=\033Oo:fq=\033OX",
     158: 		     extra_incap);
     159: 
     160: 	rc_name = findrcfile(rcfilename);
     161: 
     162: 	if (rc_name == NULL || (fp = secfopen(rc_name, "r")) == NULL) {
     163: 		const char *rc_nonnull = rc_name ? rc_name : rcfilename;
     164: 		if (!rc_recursion && RcFileName && !strcmp(RcFileName, rc_nonnull)) {
     165: 			/*
     166: 			 * User explicitly gave us that name,
     167: 			 * this is the only case, where we get angry, if we can't read
     168: 			 * the file.
     169: 			 */
     170: 			if (!nopanic)
     171: 				Panic(0, "Unable to open \"%s\".", rc_nonnull);
     172: 			/* possibly NOTREACHED */
     173: 		}
     174: 		if (rc_name)
     175: 			Free(rc_name);
     176: 		rc_name = oldrc_name;
     177: 		return 1;
     178: 	}
     179: 	while (fgets(buf, ARRAY_SIZE(buf), fp) != NULL) {
     180: 		if ((p = strrchr(buf, '\n')) != NULL)
     181: 			*p = '\0';
     182: 		if ((argc = Parse(buf, ARRAY_SIZE(buf), args, argl)) == 0)
     183: 			continue;
     184: 		if (strcmp(args[0], "echo") == 0) {
     185: 			if (!display)
     186: 				continue;
     187: 			if (argc < 2 || (argc == 3 && strcmp(args[1], "-n")) || argc > 3) {
     188: 				Msg(0, "%s: 'echo [-n] \"string\"' expected.", rc_name);
     189: 				continue;
     190: 			}
     191: 			AddStr(args[argc - 1]);
     192: 			if (argc != 3) {
     193: 				AddStr("\r\n");
     194: 				Flush(0);
     195: 			}
     196: 		} else if (strcmp(args[0], "sleep") == 0) {
     197: 			if (!display)
     198: 				continue;
     199: 			if (argc != 2) {
     200: 				Msg(0, "%s: sleep: one numeric argument expected.", rc_name);
     201: 				continue;
     202: 			}
     203: 			DisplaySleep1000(1000 * atoi(args[1]), 1);
     204: 		}
     205: 		else if (!strcmp(args[0], "termcapinfo") || !strcmp(args[0], "terminfo"))
     206: 		{
     207: 			if (!display)
     208: 				continue;
     209: 			if (argc < 3 || argc > 4) {
     210: 				Msg(0, "%s: %s: incorrect number of arguments.", rc_name, args[0]);
     211: 				continue;
     212: 			}
     213: 			for (p = args[1]; p && *p; p = cp) {
     214: 				if ((cp = strchr(p, '|')) != NULL)
     215: 					*cp++ = '\0';
     216: 				len = strlen(p);
     217: 				if (p[len - 1] == '*') {
     218: 					if (!(len - 1) || !strncmp(p, D_termname, len - 1))
     219: 						break;
     220: 				} else if (!strcmp(p, D_termname))
     221: 					break;
     222: 			}
     223: 			if (!(p && *p))
     224: 				continue;
     225: 			extra_incap = CatExtra(args[2], extra_incap);
     226: 			if (argc == 4)
     227: 				extra_outcap = CatExtra(args[3], extra_outcap);
     228: 		} else if (!strcmp(args[0], "source")) {
     229: 			if (rc_recursion <= 10) {
     230: 				rc_recursion++;
     231: 				(void)StartRc(args[1], 0);
     232: 				rc_recursion--;
     233: 			}
     234: 		}
     235: 	}
     236: 	fclose(fp);
     237: 	Free(rc_name);
     238: 	rc_name = oldrc_name;
     239: 	return 0;
     240: }

      56: static char *CatExtra(char *str1, char *str2)
      57: {
      58: 	char *cp;
      59: 	size_t len1, len2;
      60: 	bool add_colon;
      61: 
      62: 	len1 = strlen(str1);
      63: 	if (len1 == 0)
      64: 		return str2;
      65: 	add_colon = (str1[len1 - 1] != ':');
      66: 	if (str2) {
      67: 		len2 = strlen(str2);
      68: 		if ((cp = realloc(str2, len1 + len2 + add_colon + 1)) == NULL)
      69: 			Panic(0, "%s", strnomem);
      70: 		memmove(cp + len1 + add_colon, cp, len2 + 1);
      71: 	} else {
>>    72: 		if ((cp = malloc(len1 + add_colon + 1)) == NULL)
      73: 			Panic(0, "%s", strnomem);
      74: 		cp[len1 + add_colon] = '\0';
      75: 	}
      76: 	memmove(cp, str1, len1);
      77: 	if (add_colon)
      78: 		cp[len1] = ':';
      79: 
      80: 	return cp;
      81: }

