     114: 		return;
     115: 
     116: 	for (row = ldata->selected; row; row = row->next)
     117: 		if (ldata->list_fn->gl_matchrow(ldata, row, ldata->search))
     118: 			break;
     119: 
     120: 	if (!row)
     121: 		for (row = ldata->root; row != ldata->selected; row = row->next)
     122: 			if (ldata->list_fn->gl_matchrow(ldata, row, ldata->search))
     123: 				break;
     124: 
     125: 	if (row == ldata->selected)
