     515: static void WListUpdate(Window *p, ListData *ldata)
     516: {
     517: 	struct gl_Window_Data *wdata = ldata->data;
     518: 	ListRow *row, *rbefore;
     519: 	Window *before;
     520: 	int d = 0, sel = 0;
     521: 
     522: 	if (!p) {
     523: 		if (ldata->selected)
     524: 			wdata->fore = ldata->selected->data;	/* Try to retain the current selection */
     525: 		glist_remove_rows(ldata);
     526: 		gl_Window_rebuild(ldata);
     527: 		return;
     528: 	}
     529: 
     530: 	/* First decide if this window should be displayed at all. */
     531: 	d = 1;
     532: 	if (wdata->order == WLIST_NUM || wdata->order == WLIST_MRU) {
     533: 		if (p->w_group != wdata->group) {
     534: 			if (!wdata->nested)
     535: 				d = 0;
     536: 			else
     537: 				d = window_ancestor(wdata->group, p);
     538: 		}
     539: 	}
     540: 
     541: 	if (!d) {
     542: 		if (gl_Window_remove(ldata, p))
     543: 			glist_display_all(ldata);
     544: 		return;
     545: 	}
     546: 
     547: 	/* OK, so we keep the window in the list. Update the ordering.
     548: 	 * First, find the row where this window should go to. Then, either create
     549: 	 * a new row for that window, or move the exising row for the window to the
     550: 	 * correct place. */
     551: 	before = NULL;
     552: 	if (wdata->order == WLIST_MRU) {
     553: 		if (mru_window != p)
     554: 			for (before = mru_window; before; before = before->w_prev_mru)
     555: 				if (before->w_prev_mru == p)
     556: 					break;
     557: 	} else if (wdata->order == WLIST_NUM) {
     558: 		if (first_window != p)
     559: 			for (before = first_window; before; before = before->w_next)
     560: 				if (before->w_next== p)
     561: 					break;
     562: 	}
     563: 
     564: 	/* Now, find the row belonging to 'before' */
     565: 	if (before)
     566: 		rbefore = gl_Window_findrow(ldata, before);
     567: 	else if (wdata->nested && p->w_group)	/* There's no 'before'. So find the group window */
     568: 		rbefore = gl_Window_findrow(ldata, p->w_group);
     569: 	else
     570: 		rbefore = NULL;
     571: 
     572: 	/* For now, just remove the row containing 'p' if it is not already in the right place . */
     573: 	row = gl_Window_findrow(ldata, p);
     574: 	if (row) {
     575: 		if (row->prev != rbefore) {
     576: 			sel = ldata->selected->data == p;
     577: 			gl_Window_remove(ldata, p);
     578: 		} else
     579: 			p = NULL;	/* the window is in the correct place */
     580: 	}
     581: 	if (p) {
>>   582: 		row = glist_add_row(ldata, p, rbefore);
     583: 		if (sel)
     584: 			ldata->selected = row;
     585: 	}
     586: 	glist_display_all(ldata);
     587: }

