     449: void display_windows(int onblank, int order, Window *group)
     450: {
     451: 	Window *p;
     452: 	ListData *ldata;
     453: 	struct gl_Window_Data *wdata;
     454: 
     455: 	if (flayer->l_width < 10 || flayer->l_height < 6) {
     456: 		LMsg(0, "Window size too small for window list page");
     457: 		return;
     458: 	}
     459: 
     460: 	if (group) {
     461: 		onblank = 0;	/* When drawing a group window, ignore 'onblank' */
     462: 		order = (group->w_list_nested ? WLIST_NESTED : 0) +
     463: 			(group->w_list_order ? WLIST_MRU : WLIST_NUM); /* restore windowlist order flags */
     464: 	}
     465: 
     466: 	if (onblank) {
     467: 		if (!display) {
     468: 			LMsg(0, "windowlist -b: display required");
     469: 			return;
     470: 		}
     471: 		p = D_fore;
     472: 		if (p) {
     473: 			SetForeWindow(NULL);
     474: 			if (p->w_group) {
     475: 				D_fore = p->w_group;
     476: 				flayer->l_data = (char *)p->w_group;
     477: 			}
     478: 			Activate(0);
     479: 		}
     480: 		if (flayer->l_width < 10 || flayer->l_height < 6) {
     481: 			LMsg(0, "Window size too small for window list page");
     482: 			return;
     483: 		}
     484: 	} else
     485: 		p = Layer2Window(flayer);
     486: 	if (!group && p)
     487: 		group = p->w_group;
     488: 
     489: 	ldata = glist_display(&gl_Window, ListID);
     490: 	if (!ldata) {
     491: 		if (onblank && p) {
     492: 			/* Could not display the list. So restore the window. */
     493: 			SetForeWindow(p);
     494: 			Activate(1);
     495: 		}
     496: 		return;
     497: 	}
     498: 
>>   499: 	wdata = calloc(1, sizeof(struct gl_Window_Data));
     500: 	wdata->group = group;
     501: 	wdata->order = (order & ~WLIST_NESTED);
     502: 	wdata->nested = ! !(order & WLIST_NESTED);
     503: 	wdata->onblank = onblank;
     504: 
     505: 	/* Set the most recent window as selected. */
     506: 	wdata->fore = mru_window;
     507: 	while (wdata->fore && wdata->fore->w_group != group)
     508: 		wdata->fore = wdata->fore->w_prev_mru;
     509: 
     510: 	ldata->data = wdata;
     511: 
     512: 	gl_Window_rebuild(ldata);
     513: }

