      54: size_t wmb_expand(WinMsgBuf *wmb, size_t min)
      55: {
      56: 	size_t size = wmb->size;
      57: 
      58: 	if (size >= min)
      59: 		return size;
      60: 
      61: 	/* keep doubling the buffer until we reach at least the requested size; this
      62: 	 * ensures that we'll always be a power of two (so long as the original
      63: 	 * buffer size was) and doubling will help cut down on excessive allocation
      64: 	 * requests on large buffers */
      65: 	while (size < min) {
      66: 		size *= 2;
      67: 	}
      68: 
>>    69: 	void *p = realloc(wmb->buf, size);
      70: 	if (p == NULL) {
      71: 		/* reallocation failed; maybe the caller can do without? */
      72: 		return wmb->size;
      73: 	}
      74: 
      75: 	/* realloc already handled the free for us */
      76: 	wmb->buf = p;
      77: 	wmb->size = size;
      78: 	return size;
      79: }

